// Parse the analyst's JSON magazine and build the cover-image prompt.
const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;            // Ollama
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text; // Claude
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
if (!data || typeof data !== 'object') {
  data = { title: 'Security Awareness Digest', weekOf: '', intro: 'This edition could not be generated in full; please re-run.', feature: null, threats: [], awareness: [], quals: [], glossary: [] };
}
const date = (($('Aggregate Sources').first() || {}).json || {}).date || new Date().toISOString().slice(0, 10);
const title = data.title || 'Security Awareness Digest';
// Premium consulting-publication art direction: abstract/architectural rather than
// literal stock-photo office scenes — reads as a serious editorial cover.
const coverPrompt = 'Tall cover key art for a corporate security-awareness magazine titled "' + title + '". Sophisticated, restrained editorial illustration in the style of a premium management-consulting publication: abstract geometric forms, layered translucent planes and fine line work suggesting digital networks and protection; deep navy and teal palette with a single muted gold accent; generous negative space; calm, authoritative, modern. Keep the upper third quiet and dark for a masthead overlay. No close-up faces, no text, no words, no letters, no logos, no watermark, no charts, no screenshots.';
return [{ json: { data: data, title: title, date: date, coverPrompt: coverPrompt } }];

// Generate the magazine's images with the shared image provider (gpt-image-2):
// a COVER, a FEATURE hero, and one THUMBNAIL per emerging-threat card. Images are
// written to a temp work dir on disk and only FILE PATHS are set on the data —
// never base64 — so n8n execution data stays tiny (same approach as the comic
// generator). Partial outages degrade gracefully to branded placeholders rather
// than failing the whole publication.
const fs = require('fs');
const H = this.helpers;
const j = $json || {};
const data = j.data || {};
const key = $env.OPENAI_IMAGE_API_KEY || $env.OPENAI_API_KEY;
const wantImages = (($env.LEARNING_HUB_IMAGES || $env.LEARNING_HUB_COVER_IMAGE || 'true').toString().toLowerCase() !== 'false');
const base = ($env.OPENAI_BASE_URL || 'https://api.openai.com/v1');
const model = ($env.IMAGE_MODEL || 'gpt-image-2');
const QV = { low:1, medium:1, high:1, auto:1 };
let quality = String($env.LEARNING_HUB_IMAGE_QUALITY || 'high').toLowerCase(); if (!QV[quality]) quality = 'medium';
let conc = parseInt($env.IMAGE_CONCURRENCY || '3', 10); if (!(conc > 0)) conc = 3; if (conc > 8) conc = 8;
let timeout = parseInt($env.IMAGE_TIMEOUT || '120000', 10); if (!(timeout > 0)) timeout = 120000;

const A = function (x) { return Array.isArray(x) ? x : []; };
const f = data.feature || {};
const threats = A(data.threats);

const baseName = 'learning-hub-' + (j.date || new Date().toISOString().slice(0, 10));
const workDir = '/reports/learning-hub/.work/' + baseName;
try { fs.mkdirSync(workDir, { recursive: true }); } catch (e) {}

const NEG = ' No text, no words, no letters, no logos, no watermark, no charts, no screenshots, no UI.';
const STYLE = 'Sophisticated, restrained editorial illustration in the style of a premium management-consulting publication: abstract geometric forms, layered translucent planes and fine line work; deep navy and teal palette with a single muted gold accent; generous negative space; calm, authoritative, modern. No close-up faces. ';

// Build the image jobs from the magazine content.
const jobs = [];
if (j.coverPrompt) jobs.push({ id: 'cover', size: '1024x1536', prompt: j.coverPrompt });
if (f && (f.headline || f.deck)) jobs.push({ id: 'feature', size: '1536x1024', prompt: STYLE + 'Wide feature illustration for an article titled "' + (f.headline || '') + '". ' + (f.deck || '') + NEG });
threats.forEach(function (t, k) { if (t && (t.headline || t.summary)) jobs.push({ id: 'threat-' + k, idx: k, size: '1024x1024', prompt: STYLE + 'Conceptual thumbnail illustrating: ' + (t.headline || '') + '. ' + (t.summary || '') + NEG }); });

async function mapLimit(items, limit, fn) {
  const ret = new Array(items.length); let idx = 0;
  async function worker() { while (idx < items.length) { const cur = idx++; ret[cur] = await fn(items[cur], cur); } }
  const n = Math.max(1, Math.min(limit, items.length));
  const workers = []; for (let w = 0; w < n; w++) workers.push(worker());
  await Promise.all(workers);
  return ret;
}
async function gen(prompt, size) {
  const resp = await H.httpRequest({ method: 'POST', url: base + '/images/generations',
    headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
    body: { model: model, prompt: prompt, size: size, quality: quality, n: 1 }, json: true, timeout: timeout });
  return resp && resp.data && resp.data[0] && resp.data[0].b64_json;
}

let cover = '', ok = 0, failed = 0;
if (wantImages && key && jobs.length) {
  const results = await mapLimit(jobs, conc, async function (job) {
    let file = '';
    try {
      const b64 = await gen(job.prompt, job.size);
      if (b64) { file = workDir + '/' + job.id + '.png'; fs.writeFileSync(file, Buffer.from(b64, 'base64')); ok++; }
      else failed++;
    } catch (e) { failed++; }
    return { id: job.id, idx: job.idx, file: file };
  });
  results.forEach(function (r) {
    if (!r.file) return;
    if (r.id === 'cover') cover = r.file;
    else if (r.id === 'feature') f.image = r.file;
    else if (r.id.indexOf('threat-') === 0 && threats[r.idx]) threats[r.idx].image = r.file;
  });
}

return [{ json: Object.assign({}, j, { data: data, cover: cover, workDir: workDir, imagesGenerated: ok, imagesFailed: failed }) }];

// Render the staff security-awareness magazine to McKinsey-grade editorial spec:
// a restrained full-bleed cover (separate PDF pass, no footer) plus body pages with
// generous whitespace, hairline rules, numbered sections, an "At a glance" stat
// band, Exhibit-captioned imagery, a large serif pull quote and page-number footers
// (Gotenberg header/footer pass, merged with the cover downstream).
// Returns coverHtml + bodyHtml + headerHtml + footerHtml alongside the parsed data.
const j = $json || {};
const data = j.data || {};
const date = j.date || new Date().toISOString().slice(0, 10);
const title = j.title || data.title || 'Security Awareness Digest';
const weekOf = data.weekOf || '';
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
const A = function(x){ return Array.isArray(x)?x:[]; };
function firstSentence(s){ var m=String(s||'').match(/^[\s\S]*?[.!?](\s|$)/); return (m?m[0]:String(s||'')).trim(); }

const f = data.feature || {};
const threats = A(data.threats), aw = A(data.awareness), quals = A(data.quals), gloss = A(data.glossary);
const glance = A(data.atAGlance).filter(function(g){ return g && (g.value || g.label); }).slice(0,3);
const standfirst = data.standfirst || (data.intro ? firstSentence(data.intro) : '');

// Env-driven brand theme (platform standard).
function jbHex(v,d){v=String(v||'').trim();return /^#[0-9a-fA-F]{6}$/.test(v)?v:d;}
var JB_PRI=jbHex($env.BRAND_PRIMARY,'#0A1A2F'),JB_ACC=jbHex($env.BRAND_ACCENT,'#0E7C86'),JB_GOLD=jbHex($env.BRAND_GOLD,'#C9A24B');

// Jarvis sign-off avatar: prefer the shared branding file, else inline SVG.
let _fs = null; try { _fs = require('fs'); } catch (e) {}
function avatarUri(){ if (_fs) { var t = [['/config/branding/jarvis-avatar.png','image/png'],['/config/branding/jarvis-avatar.jpg','image/jpeg'],['/config/branding/jarvis-avatar.jpeg','image/jpeg'],['/config/branding/jarvis-avatar.svg','image/svg+xml']]; for (var i=0;i<t.length;i++){ try { return 'data:' + t[i][1] + ';base64,' + _fs.readFileSync(t[i][0]).toString('base64'); } catch(e){} } } return ''; }
// Images arrive as on-disk file paths (from Generate Images) — read each one
