function imgSrc(p){ if (!p) return ''; var v = String(p); if (v.indexOf('data:') === 0) return v; if (_fs) { try { return 'data:image/png;base64,' + _fs.readFileSync(v).toString('base64'); } catch (e) {} } return ''; }
const cover = imgSrc(j.cover);
const featureImg = imgSrc(f.image);
