 + '<div class="plate'+(cover?'':' ph')+'"'+(cover?(' style="background-image:url('+cover+')"'):'')+'><div class="edge"></div></div>'
 + (sectionNames.length ? ('<div class="toc"><div class="in"><div class="tl">In this issue</div><ul>'
