 + '</div></body></html>';

// ---------- body ----------
let secNo = 0;
function shead(eyebrow, t){ secNo++; return '<div class="shead"><div class="no">'+String(secNo).padStart(2,'0')+'</div><div class="ttl"><div class="eyebrow">'+esc(eyebrow)+'</div><h2>'+esc(t)+'</h2></div></div>'; }
function body2col(text){ var ps = String(text||'').split(/\n+/).map(function(s){return s.trim();}).filter(Boolean); if(!ps.length) return ''; var lead = '<p class="lead">' + esc(ps[0]) + '</p>'; var rest = ps.slice(1).map(function(p){return '<p>' + esc(p) + '</p>';}).join(''); return lead + (rest ? ('<div class="cols">' + rest + '</div>') : ''); }

let body = '<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body>';
// at a glance — the consulting-style stat band
if (glance.length) {
  body += '<div class="glance"><div class="ghead"><div class="gh">At a<br>glance</div></div>'
    + glance.map(function(g){ return '<div class="g">'+(g.value?('<div class="v">'+esc(g.value)+'</div>'):'')+'<div class="d">'+esc(g.label||'')+'</div></div>'; }).join('')
    + '</div>';
}
// editorial
if (data.intro) {
  body += '<section class="sec">' + shead('From the editor', 'Welcome to this edition') + body2col(data.intro) + '</section>';
}
// feature
if (f && (f.headline || f.body)) {
  const pull = f.pullQuote || (A(f.takeaways)[0]) || '';
  body += '<section class="sec flow">' + shead('Feature', f.headline || 'In focus')
    + (f.deck ? ('<div class="deck">'+esc(f.deck)+'</div>') : '')
    + (featureImg ? ('<div class="exhibit"><div class="img" style="background-image:url('+featureImg+')"></div><div class="cap"><b>Exhibit 1</b> &nbsp;'+esc(f.deck||f.headline||'')+'</div></div>') : '')
    + body2col(f.body || '')
    + (pull ? ('<div class="pull"><div class="q">&ldquo;'+esc(pull)+'&rdquo;</div></div>') : '')
    + (A(f.takeaways).length ? ('<div class="bottomline"><div class="th">The bottom line</div><ul>' + A(f.takeaways).map(function(t){return '<li>'+esc(t)+'</li>';}).join('') + '</ul></div>') : '')
    + '</section>';
}
// threat radar
if (threats.length) {
  body += '<section class="sec flow">' + shead('Threat radar', 'Emerging Threats')
    + threats.map(function(t,i){ var tu=imgSrc(t.image); return '<div class="titem"><div class="tn">'+String(i+1).padStart(2,'0')+'</div>'+(tu?('<div class="timg" style="background-image:url('+tu+')"></div>'):'')+'<div class="tb"><h3>'+esc(t.headline||'')+'</h3><p>'+esc(t.summary||'')+'</p>'+(t.source?('<div class="src">'+esc(t.source)+'</div>'):'')+'</div></div>'; }).join('')
    + '</section>';
}
// human firewall
if (aw.length) {
  body += '<section class="sec flow">' + shead('Practical habits', 'The Human Firewall')
    + '<div class="habits">' + aw.map(function(a,i){ return '<div class="habit"><span class="hn">'+(i+1)+'</span><h3>'+esc(a.tip||'')+'</h3><p>'+esc(a.detail||'')+'</p></div>'; }).join('') + '</div></section>';
}
// skills
if (quals.length) {
  body += '<section class="sec flow">' + shead('Grow your skills', 'Skills & Qualifications')
    + quals.map(function(q){ return '<div class="qual"><div class="prov">'+esc(q.provider||'')+'</div><h3>'+esc(q.name||'')+'</h3><p>'+esc(q.summary||'')+'</p></div>'; }).join('') + '</section>';
}
// glossary
if (gloss.length) {
  body += '<section class="sec flow">' + shead('Plain English', 'Jargon Buster')
    + '<div class="gloss">' + gloss.map(function(g){ return '<div class="gterm"><b>'+esc(g.term||'')+'</b> &mdash; '+esc(g.definition||'')+'</div>'; }).join('') + '</div></section>';
}
// sign-off (subtle) + references
const AV = avatarUri();
body += '<div class="signoff">' + (AV ? ('<img src="' + AV + '"/>') : JARVIS_SVG) + '<div><div class="nm">Jarvis</div><div class="rl">Your AI Awareness Editor</div></div></div>';
const refs = [];
if (f && f.url) refs.push({ s: f.source || f.headline || 'Feature', u: f.url });
threats.forEach(function(t){ if (t && t.url) refs.push({ s: t.source || t.headline || 'Threat report', u: t.url }); });
quals.forEach(function(q){ if (q && q.url) refs.push({ s: q.provider || q.name || 'Course', u: q.url }); });
if (refs.length) {
  body += '<section class="sec flow refs">' + shead('Sources', 'References & Further Reading')
    + '<ol>' + refs.map(function(r, i){ return '<li><span class="rn">' + (i+1) + '.</span> <b>' + esc(r.s) + '</b><br><a href="' + esc(r.u) + '">' + esc(r.u) + '</a></li>'; }).join('') + '</ol></section>';
}
body += '</body></html>';

// ---------- Gotenberg running header / page-number footer (body pages only) ----------
const headerHtml = '<!doctype html><html><head><style>body{margin:0;font-family:Georgia,serif}'
 + '.h{display:flex;justify-content:space-between;align-items:center;font-size:7.5pt;color:#8a93a0;padding:5mm 18mm 0;width:100%;letter-spacing:2px;text-transform:uppercase;font-family:Arial,sans-serif}'
 + '</style></head><body><div class="h"><span>'+esc(title)+'</span><span>'+esc(weekOf||date)+'</span></div></body></html>';
const footerHtml = '<!doctype html><html><head><style>body{margin:0}'
 + '.f{display:flex;justify-content:space-between;align-items:center;font-size:7.5pt;color:#8a93a0;padding:0 18mm 4mm;width:100%;font-family:Arial,sans-serif;letter-spacing:1px}'
 + '.f .pg{color:'+JB_PRI+';font-weight:700}'
 + '</style></head><body><div class="f"><span>Security Awareness &middot; Learning Hub</span><span class="pg"><span class="pageNumber"></span></span></div></body></html>';

// The HTMLs embed multi-MB images — write them to the work dir and pass only
// file paths through node JSON (hardened pattern; Write Magazine cleans up).
const workDir = j.workDir || ('/reports/learning-hub/.work/learning-hub-' + date);
try { _fs.mkdirSync(workDir, { recursive: true }); } catch (e) {}
function put(name, content){ var p = workDir + '/' + name; _fs.writeFileSync(p, content); return p; }
const files = {
  cover: put('cover.html', coverHtml),
  body: put('body.html', body),
  header: put('header.html', headerHtml),
  footer: put('footer.html', footerHtml)
